commands.examples:
-- Contains
SELECT * FROM configs WHERE data @> '{"theme": "dark"}';

-- Key exists
SELECT * FROM configs WHERE data ? 'notifications';

-- Any key exists
SELECT * FROM configs WHERE data ?| ARRAY['theme', 'lang'];

-- All keys exist
SELECT * FROM configs WHERE data ?& ARRAY['theme', 'lang'];

-- Set value
UPDATE configs SET data = jsonb_set(data, '{theme}', '"light"');

-- Set nested value
UPDATE users SET profile = jsonb_set(profile, '{address,city}', '"Jakarta"');

-- Hapus key
UPDATE configs SET data = data - 'old_key';

-- Merge
UPDATE configs SET data = data || '{"new_key": "value"}'::jsonb;

-- Hapus nested
UPDATE users SET profile = profile #- '{address,zip}';

-- Expand object
SELECT key, value FROM jsonb_each('{"a":1,"b":2}'::jsonb);

-- Expand array
SELECT * FROM jsonb_array_elements('[1,2,3]'::jsonb);

-- Practical: search in JSONB array
SELECT * FROM users
WHERE EXISTS (
  SELECT 1 FROM jsonb_array_elements_text(profile->'hobbies') h
  WHERE h.value ILIKE '%music%'
);

-- JSONB to record
SELECT * FROM jsonb_to_record('{"name":"John","age":30}'::jsonb)
AS x(name TEXT, age INT);

SELECT jsonb_build_object('name', name, 'email', email) FROM users;
SELECT jsonb_build_array(1, 'two', 3);
SELECT row_to_json(u) FROM users u;
SELECT to_jsonb(u.*) FROM users u;

-- API-style response
SELECT jsonb_build_object(
  'status', 'success',
  'data', jsonb_agg(to_jsonb(u.*)),
  'count', count(*)
) FROM users u WHERE active = true;
